const base64String = $json["verilog_text"];
const decodedText = Buffer.from(base64String, "base64").toString("utf8");

return [{
  json: {
    prompt: decodedText   // pass raw source — Verilog Analyser will summarise it
  }
}];

let history = [];
try {
  history = $node["update counter"].json.history || [];
} catch (e) {
  history = [];
}

const geminiJson = $node["Message a model"].json;
let testbenchText = "";
if (geminiJson.candidates && geminiJson.candidates[0] && geminiJson.candidates[0].content) {
  testbenchText = geminiJson.candidates[0].content.parts[0].text || "";
} else if (geminiJson.text) {
  testbenchText = geminiJson.text;
}

// Generic regex — matches any: fault_buffer = uut.<anything> ^ (N'h1 << BIT)
const bitMatch = testbenchText.match(/fault_buffer\s*=\s*uut\.\w+\s*\^\s*\(\d+'h1\s*<<\s*(\d+)\)/);
const currentBit = bitMatch ? bitMatch[1] : null;

if (currentBit !== null && !isNaN(currentBit)) {
  history.push(parseInt(currentBit));
}

return [{
  json: {
    counter: $runIndex + 1,
    history: history,
    current_bit: currentBit,
    max_trials: 4
  }
}];

// Use the built-in runIndex to track the loop count
const currentRun = $runIndex; // Starts at 0, 1, 2...

return {
  counter: currentRun + 1,
  // This tells the IF node exactly when to stop
  isFinished: currentRun >= 9 
};

// Unify both Merge inputs into clean items with output field
return $input.all().map(item => ({
  json: {
    output: item.json.output || "",
    error_msg: item.json.error_msg || item.json.error || null,
    statusCode: item.json.statusCode || null,
    memory: item.json.memory || null,
    cpuTime: item.json.cpuTime || null,
    isExecutionSuccess: item.json.isExecutionSuccess || false,
    isCompiled: item.json.isCompiled || false
  }
}));

// 1. Reach back to get everything from the HTTP Request history
const allHistory = $('HTTP Request').all();

// 2. Wrap each item inside a "json" key to avoid the "error" key conflict
return allHistory.map((item) => {
  return {
    json: {
      output: item.json.output,
      error_msg: item.json.error || null, // Renamed to avoid reserved word issues
      statusCode: item.json.statusCode,
      memory: item.json.memory,
      cpuTime: item.json.cpuTime,
      compilationStatus: item.json.compilationStatus,
      projectKey: item.json.projectKey,
      isExecutionSuccess: item.json.isExecutionSuccess,
      isCompiled: item.json.isCompiled
    }
  };
});

return $input.all().map((item, index) => {
  const log = String(item.json.output || "");

  const pcMatch  = log.match(/Old\s*PC\s*=\s*([0-9a-fA-F]+)\s*,\s*New\s*PC\s*=\s*([0-9a-fA-F]+)/i);
  const bitMatch = log.match(/Bit\s*(\d+)\s*flipped/i);

  const oldPCStr = pcMatch ? pcMatch[1].padStart(8, '0') : "00000000";
  const newPCStr = pcMatch ? pcMatch[2].padStart(8, '0') : "00000000";
  const oldPC    = parseInt(oldPCStr, 16);
  const newPC    = parseInt(newPCStr, 16);
  const jump     = newPC - oldPC;

  let outcome = "No Effect";
  if (jump !== 0) {
    outcome = (newPC % 4 !== 0) ? "Critical: Alignment Crash" : "Success: Control Flow Hijack";
  }

  return {
    json: {
      trial: index + 1,
      bit_targeted: bitMatch ? bitMatch[1] : "N/A",
      pc_before: oldPCStr,
      pc_after:  newPCStr,
      jump_distance_bytes: jump,
      abs_jump:  Math.abs(jump),
      severity:  (Math.abs(jump) > 1000) ? "High" : (Math.abs(jump) > 4 ? "Medium" : "Low"),
      result_summary: outcome,
      output: item.json.output || ""
    }
  };
});

function geminiText(nodeData) {
  const d = nodeData.first().json;
  if (d.candidates && d.candidates[0] && d.candidates[0].content) {
    return d.candidates[0].content.parts[0].text || "";
  }
  if (d.text) return d.text;
  return JSON.stringify(d);
}

function cleanVerilog(src) {
  // Strip markdown fences
  src = src.replace(/```verilog|```/gi, '').trim();
  // Collapse multiple trailing endmodule into exactly one
  src = src.replace(/(\bendmodule\b\s*)+$/i, 'endmodule');
  return src.trim();
}

let testbench = geminiText($('Message a model'));
const meta    = $('Parse Analyser').first().json;
let cpuCode   = meta.decoded || '';

testbench = cleanVerilog(testbench);
cpuCode   = cleanVerilog(cpuCode);

if (!testbench) throw new Error("Message a model produced no testbench output");
if (!cpuCode)   throw new Error("Source Code produced no decoded output");

// If LLM inlined the DUT definition inside the testbench, remove it
const dutName = (meta.module_name || '').replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
if (dutName) {
  const inlineRe = new RegExp('module\\s+' + dutName + '\\b[\\s\\S]*?endmodule', 'gi');
  testbench = testbench.replace(inlineRe, '').trim();
}


// Sanitize testbench: remove any wire/reg declarations that duplicate
// an already-used implicit net (the most common LLM mistake: declaring
// a wire AFTER it was already used in a port connection list).
// Strategy: remove lines that declare wires for output ports we don't need.
testbench = testbench
  .split('\n')
  .filter(line => {
    // Drop lines like: wire [N:0] <something>_monitor; or wire <name>;
    // that are ONLY used as output-port sinks (not driven anywhere else)
    const isOutputSinkDecl = /^\s*wire\s+.*\bmonitor\b.*;/.test(line) ||
                             /^\s*wire\s+\[.*\]\s+\w+\s*;/.test(line) && 
                             !line.includes('//');
    return !isOutputSinkDecl;
  })
  .join('\n');





// ── Port + Register enforcer ──────────────────────────────────────────────
// Fixes: wrong port names, missing bit-widths on reg declarations,
//        hallucinated uut.<reg> references throughout the testbench body.
(function enforcePortsAndRegs() {
  const name      = (meta.module_name        || '').trim();
  const ports     = (meta.all_ports          || '').trim();
  const portDecls = (meta.port_declarations  || '').trim();
  const correctReg = (meta.primary_state_reg || '').trim();
  const regWidth   = parseInt(meta.primary_reg_width) || 8;

  if (!name || !ports) return;

  const portList = ports.split(',').map(p => p.trim()).filter(Boolean);

  // Determine output vs input and extract bit-width from port_declarations
  // e.g. "output reg [7:0] pc;" → port "pc" is output, width "[7:0]"
  function getPortWidth(portName) {
    const re = new RegExp(
      '(?:input|output)\\s+(?:reg\\s+|wire\\s+)?(\\[\\d+:\\d+\\])?\\s*' + portName + '\\b'
    );
    const m = portDecls.match(re);
    return m && m[1] ? m[1] : '';   // e.g. "[7:0]" or ""
  }

  function isOutput(portName) {
    return new RegExp('output[^;]*\\b' + portName + '\\b').test(portDecls);
  }

  // Build canonical instantiation
  const connLines = portList.map(p => {
    if (isOutput(p)) return `    .${p}()`;
    return `    .${p}(${p})`;
  }).join(',\n');
  const newInst = `${name} uut (\n${connLines}\n);`;

  // Replace any existing instantiation block
  testbench = testbench.replace(
    /\b\w+\s+uut\s*\([\s\S]*?\)\s*;/,
    newInst
  );

  // Fix reg declarations — remove ALL existing input-port reg declarations
  // then re-inject them with correct widths
  portList.forEach(p => {
    if (!isOutput(p)) {
      // Remove old (possibly wrong-width) declaration
      testbench = testbench.replace(
        new RegExp('\\breg\\s+(?:\\[\\d+:\\d+\\]\\s+)?' + p + '\\s*;\\s*\\n?', 'g'),
        ''
      );
    }
  });

  // Re-inject correct declarations after "module test;"
  const newDecls = portList
    .filter(p => !isOutput(p))
    .map(p => {
      const w = getPortWidth(p);
      return `reg ${w ? w + ' ' : ''}${p};`;
    })
    .join('\n');

  testbench = testbench.replace(
    /(module\s+test\s*;\s*\n)/,
    `$1${newDecls}\n`
  );

  // ── Fix ALL uut.<wrongReg> references in the testbench body ────────────
  if (correctReg) {
    // Collect every signal name used after "uut." in the testbench
    const usedRegs = [...testbench.matchAll(/\buut\.(\w+)/g)].map(m => m[1]);
    const wrongRegs = [...new Set(usedRegs)].filter(r => r !== correctReg);
    wrongRegs.forEach(wr => {
      const wrRe = new RegExp('\\buut\\.' + wr.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '\\b', 'g');
      testbench = testbench.replace(wrRe, 'uut.' + correctReg);
    });

    // Fix width of fault_buffer and state_before_fault declarations
    const wStr = regWidth > 1 ? `[${regWidth-1}:0] ` : '';
    testbench = testbench.replace(
      /\breg\s+(?:\[\d+:\d+\]\s+)?state_before_fault\s*;/g,
      `reg ${wStr}state_before_fault;`
    );
    testbench = testbench.replace(
      /\breg\s+(?:\[\d+:\d+\]\s+)?fault_buffer\s*;/g,
      `reg ${wStr}fault_buffer;`
    );

    // Fix the fault-injection width literal: 8'h1, 32'h1, etc.
    testbench = testbench.replace(
      /\d+'h1\s*<</g,
      `${regWidth}'h1 <<`
    );
  }
})();
// ─────────────────────────────────────────────────────────────────────────

// ── Module-name enforcer ──────────────────────────────────────────────────
// The LLM sometimes instantiates a hallucinated module name instead of the
// real DUT name. Detect this and replace every wrong instantiation with the
// correct module name from Parse Analyser metadata.
const correctName = (meta.module_name || '').trim();
if (correctName) {
  // Find what module name the testbench actually used for "uut"
  const usedNameMatch = testbench.match(/\b(\w+)\s+uut\s*\(/);
  const usedName = usedNameMatch ? usedNameMatch[1] : null;
  if (usedName && usedName !== correctName && usedName !== 'module') {
    // Replace all occurrences of the wrong name in the testbench
    const wrongRe = new RegExp('\\b' + usedName.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '\\b', 'g');
    testbench = testbench.replace(wrongRe, correctName);
    // Also fix any wrong internal signal references (e.g. uut.count → uut.pc)
    // by replacing wrong register names with the known primary state reg
    const correctReg = (meta.primary_state_reg || '').trim();
    if (correctReg) {
      // Find what reg name the LLM used after "uut."
      const wrongRegMatches = [...testbench.matchAll(/uut\.(\w+)/g)].map(m => m[1]);
      const wrongRegs = [...new Set(wrongRegMatches)].filter(r => r !== correctReg);
      for (const wr of wrongRegs) {
        const wrRe = new RegExp('\\buut\\.' + wr.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '\\b', 'g');
        testbench = testbench.replace(wrRe, 'uut.' + correctReg);
      }
    }
  }
}
// ─────────────────────────────────────────────────────────────────────────
// DUT first so the module is defined before the testbench instantiates it
const combined_script = cpuCode + '\n\n' + testbench;

return [{ json: { combined_script } }];

const attackLogs = $('Log Generator').all();

// Validation Log Parser may have run multiple times — get last result
let valItem;
try { valItem = $('Validation Log Parser').first().json; }
catch(e) { valItem = {}; }

// Retry attempt count
const retryAttempt = (() => {
  try { return $('Hardening Loop Init').first().json.retry_attempt || 0; }
  catch(e) { return 0; }
})();

const phase1Lines = attackLogs.map(t => {
  const j = t.json;
  return `  Trial ${j.trial}: Bit ${j.bit_targeted} | PC ${j.pc_before} -> ${j.pc_after} | Jump: ${j.jump_distance_bytes}B | ${j.result_summary}`;
}).join('\n') || '  (no trials recorded)';

const jump = Math.abs(valItem.jump_distance_bytes || 0);
const mitigated = !valItem.still_vulnerable || jump <= 4;

const report = [
  '========================================',
  '  HARDWARE SECURITY DISCLOSURE REPORT',
  '========================================',
  '',
  'PHASE 1 - FAULT INJECTION CAMPAIGN',
  '------------------------------------',
  phase1Lines,
  '',
  'PHASE 2 - MITIGATION APPLIED',
  '------------------------------------',
  '  Strategy : Triple Modular Redundancy (TMR) on Program Counter',
  `  Attempts  : ${retryAttempt > 0 ? retryAttempt + 1 : 1} hardening iteration(s)`,
  '  Details   : Shadow registers pc_1/pc_2/pc_3 + majority voter',
  '',
  'PHASE 3 - VALIDATION RESULT',
  '------------------------------------',
  `  Bit Re-Attacked : ${valItem.bit_targeted || 'N/A'}`,
  `  PC Before Flip  : ${valItem.pc_before   || 'N/A'}`,
  `  PC After Flip   : ${valItem.pc_after    || 'N/A'}`,
  `  Jump Distance   : ${valItem.jump_distance_bytes || 0} bytes`,
  `  Mitigation      : ${mitigated
      ? 'CONFIRMED - 100% Mitigation Successful'
      : 'MAX RETRIES REACHED - Partial mitigation only'}`,
  '',
  '========================================',
  `  Generated: ${new Date().toISOString()}`,
  '========================================',
].join('\n');

return [{ json: {
  disclosure_report: report,
  summary_prompt: 'Rewrite as a polished executive-level security advisory with sections: Executive Summary, Vulnerability Details, Mitigation Applied, Validation Results, Recommendations.\n\n' + report
}}];

