return $input.all().map(item => {
  const j = item.json;
  const jump    = Math.abs(j.jump_distance_bytes || 0);
  const newPC   = parseInt(j.pc_after  || "0", 16);
  const raw     = String(j.output || "").toLowerCase();

  const isMisaligned = (newPC % 4 !== 0) && newPC !== 0;
  const isLargeJump  = jump > 4;
  const isHijack     = j.result_summary === "Success: Control Flow Hijack";
  const isAlignCrash = j.result_summary === "Critical: Alignment Crash";
  const isCrash      = raw.includes("segmentation fault")
                    || raw.includes("fatal error")
                    || raw.includes("runtime error");

  const is_serious = isMisaligned || isLargeJump || isHijack || isAlignCrash || isCrash;

  const severity_reason =
    isAlignCrash ? "Critical: Instruction Misalignment" :
    isHijack     ? "Critical: Control Flow Hijacked"    :
    isLargeJump  ? `High: Major PC Jump (${jump} bytes)` :
    isMisaligned ? "High: PC Misalignment"              :
    isCrash      ? "High: Runtime Crash"                :
                   "Masked: Negligible/No Effect";

  return {
    json: {
      ...j,
      jump_distance: jump,
      is_serious,
      severity_reason
    }
  };
});

// Items that are not serious errors — label as Masked and stop
return $input.all().map(item => ({
  json: { ...item.json, final_status: 'Masked — No Action Required' }
}));

const all = $input.all();
const serious = all.filter(i => i.json.is_serious === true);
const masked  = all.filter(i => i.json.is_serious !== true);

const vulnReport = serious.map(i => {
  const j = i.json;
  return `  - Trial ${j.trial}: Bit ${j.bit_targeted} | PC ${j.pc_before} -> ${j.pc_after} | Jump: ${j.jump_distance_bytes}B | ${j.severity_reason} | ${j.result_summary}`;
}).join("\n");

const maskedReport = masked.map(i => {
  const j = i.json;
  return `  - Trial ${j.trial}: Bit ${j.bit_targeted} | ${j.severity_reason}`;
}).join("\n");

if (serious.length === 0) {
  return [{
    json: {
      has_serious: false,          // explicit boolean false
      vuln_report: "No serious faults detected.\n" + maskedReport,
      masked_report: maskedReport,
      total_trials: all.length,
      serious_count: 0
    }
  }];
}

return [{
  json: {
    has_serious: true,             // explicit boolean true
    vuln_report: vulnReport,
    masked_report: maskedReport,
    total_trials: all.length,
    serious_count: serious.length,
    worst_bit:       serious[0].json.bit_targeted,
    worst_jump:      serious[0].json.jump_distance_bytes,
    worst_pc_before: serious[0].json.pc_before,
    worst_pc_after:  serious[0].json.pc_after
  }
}];

